mapper.select:
SELECT COUNT(DISTINCT op.opid)
FROM c_owner_property op
LEFT JOIN t_vote_item vi
       ON vi.subject_id = #{subjectId}
      AND vi.opid = op.opid
WHERE op.tenant_id = #{tenantId}
  AND op.building_id = #{buildingId}
  AND op.account_status = 1
  AND vi.vote_id IS NULL

mapper.insert:
INSERT INTO t_voting_mobilization_reminder (
    subject_id, tenant_id, building_id, sent_by_user_id, permission_id,
    target_scope, target_count, message_template, message, outbox_event_id, sent_at
) VALUES (
    #{subjectId}, #{tenantId}, #{buildingId}, #{sentByUserId}, #{permissionId},
    #{targetScope}, #{targetCount}, #{messageTemplate}, #{message}, #{outboxEventId}, #{sentAt}
)
